import fs from 'node:fs';
import path from 'node:path';
import { execSync } from 'node:child_process';
import postgres from 'postgres';

const DOCUMENT_ID = '9d09fa89-3a46-465e-a98b-837287c9e22a';
const url = process.env.PROD_URL || process.env.DIRECT_URL || process.env.DATABASE_URL;
const mode = process.argv[2];
const outDir = process.env.OUT_DIR || process.cwd();

if (!url) throw new Error('Set PROD_URL, DIRECT_URL, or DATABASE_URL');
if (!['old', 'new', 'compare'].includes(mode)) {
  throw new Error('Usage: node export-compare.mjs old|new|compare');
}

fs.mkdirSync(outDir, { recursive: true });

const sql = postgres(url, { max: 1, prepare: false, connect_timeout: 30 });

const q = async (strings, ...values) => sql.unsafe(String.raw({ raw: strings }, ...values));

function run(command) {
  try {
    return execSync(command, { cwd: process.cwd(), encoding: 'utf8', stdio: ['ignore', 'pipe', 'pipe'] }).trim();
  } catch (error) {
    return `ERROR: ${error.message}\n${error.stderr?.toString?.() ?? ''}`.trim();
  }
}

function normText(value) {
  return String(value ?? '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function mdEscape(value) {
  return String(value ?? '').replace(/\|/g, '\\|').replace(/\r?\n/g, '<br>');
}

function countBy(rows, keys) {
  const out = {};
  for (const row of rows) {
    const key = keys.map((k) => row[k] ?? '(none)').join(' / ');
    out[key] = (out[key] ?? 0) + 1;
  }
  return Object.fromEntries(Object.entries(out).sort(([a], [b]) => a.localeCompare(b)));
}

function rowsBy(rows, keyFn) {
  const map = new Map();
  for (const row of rows) {
    const key = keyFn(row);
    if (!key) continue;
    const bucket = map.get(key) ?? [];
    bucket.push(row);
    map.set(key, bucket);
  }
  return map;
}

function summarizeClaims(claims) {
  return {
    total: claims.length,
    byStatus: countBy(claims, ['status']),
    byClaimType: countBy(claims, ['claim_type']),
    byClaimKind: countBy(claims, ['claim_kind']),
    byStatusTypeKind: countBy(claims, ['status', 'claim_type', 'claim_kind']),
    byDomain: countBy(
      claims.flatMap((claim) => (claim.top_domains?.length ? claim.top_domains : ['(none)']).map((domain) => ({ domain }))),
      ['domain'],
    ),
  };
}

function claimTable(claims) {
  const lines = [
    '| # | Status | Type | Kind | Domains | Summary | Quote |',
    '|---:|---|---|---|---|---|---|',
  ];
  claims.forEach((claim, index) => {
    const quote = claim.evidence?.[0]?.quote ?? claim.evidence?.[0]?.source_quote ?? '';
    lines.push(
      `| ${index + 1} | ${mdEscape(claim.status)} | ${mdEscape(claim.claim_type)} | ${mdEscape(claim.claim_kind)} | ${mdEscape((claim.top_domains ?? []).join(', '))} | ${mdEscape(claim.summary)} | ${mdEscape(quote)} |`,
    );
  });
  return lines.join('\n');
}

async function tableExists(tableName) {
  const [row] = await sql`
    select to_regclass(${tableName}) as name
  `;
  return Boolean(row?.name);
}

