async function compareSnapshots() {
  const oldPath = path.join(outDir, 'old-claims-before-rerun.json');
  const newPath = path.join(outDir, 'new-claims-after-rerun.json');
  const oldData = JSON.parse(fs.readFileSync(oldPath, 'utf8'));
  const newData = JSON.parse(fs.readFileSync(newPath, 'utf8'));
  const oldClaims = oldData.claims ?? [];
  const newClaims = newData.claims ?? [];

  const oldSummarySet = new Set(oldClaims.map((claim) => claim.summary));
  const newSummarySet = new Set(newClaims.map((claim) => claim.summary));
  const exactSummaryOverlap = [...oldSummarySet].filter((summary) => newSummarySet.has(summary)).sort();

  const quoteOf = (claim) => claim.evidence?.[0]?.quote ?? claim.evidence?.[0]?.source_quote ?? '';
  const oldQuoteSet = new Set(oldClaims.map((claim) => normText(quoteOf(claim))).filter(Boolean));
  const newQuoteSet = new Set(newClaims.map((claim) => normText(quoteOf(claim))).filter(Boolean));
  const normalizedQuoteOverlap = [...oldQuoteSet].filter((quote) => newQuoteSet.has(quote)).sort();

  const oldNormSummaries = new Set(oldClaims.map((claim) => normText(claim.summary)));
  const newNormSummaries = new Set(newClaims.map((claim) => normText(claim.summary)));
  const oldClaimsLost = oldClaims.filter((claim) => !newNormSummaries.has(normText(claim.summary)));
  const newClaimsGained = newClaims.filter((claim) => !oldNormSummaries.has(normText(claim.summary)));

  const duplicateSummaryGroups = [...rowsBy(newClaims, (claim) => normText(claim.summary)).values()]
    .filter((group) => group.length > 1)
    .map((group) => ({
      count: group.length,
      summary: group[0].summary,
      claimIds: group.map((claim) => claim.id),
      quotes: [...new Set(group.map(quoteOf))],
    }));
  const duplicateQuoteGroups = [...rowsBy(newClaims, (claim) => normText(quoteOf(claim))).values()]
    .filter((group) => group.length > 1)
    .sort((a, b) => b.length - a.length)
    .slice(0, 25)
    .map((group) => ({
      count: group.length,
      quote: quoteOf(group[0]),
      claimIds: group.map((claim) => claim.id),
      summaries: group.map((claim) => claim.summary),
    }));

  const newlyCapturedRelationships = (newData.macroRelationships ?? []).map((rel) => ({
    id: rel.id,
    status: rel.status,
    relationshipType: rel.relationship_type,
    summary: rel.summary,
    confidenceScore: rel.confidence_score,
    impactScore: rel.impact_score,
  }));

  const comparison = {
    generatedAt: new Date().toISOString(),
    outDir,
    documentId: DOCUMENT_ID,
    old: {
      generatedAt: oldData.generatedAt,
      total: oldClaims.length,
      counts: oldData.summary.claims,
      chunks: oldData.summary.chunks,
      outlines: oldData.summary.sourceOutlines,
      macroRelationships: oldData.summary.macroRelationships,
      coverageFindings: oldData.summary.coverageFindings,
    },
    new: {
      generatedAt: newData.generatedAt,
      total: newClaims.length,
      counts: newData.summary.claims,
      chunks: newData.summary.chunks,
      outlines: newData.summary.sourceOutlines,
      macroRelationships: newData.summary.macroRelationships,
      coverageFindings: newData.summary.coverageFindings,
    },
    overlap: {
      exactSummaryCount: exactSummaryOverlap.length,
      exactSummaries: exactSummaryOverlap,
      normalizedQuoteCount: normalizedQuoteOverlap.length,
      normalizedQuoteOverlap,
      oldUniqueNormalizedQuoteCount: oldQuoteSet.size,
      newUniqueNormalizedQuoteCount: newQuoteSet.size,
    },
    obviousDuplicatesInNewClaims: {
      duplicateSummaryGroups,
      duplicateQuoteGroups,
    },
    newlyCapturedImportantRelationships: newlyCapturedRelationships,
    oldClaimsLost: oldClaimsLost.map((claim) => ({
      id: claim.id,
      status: claim.status,
      claimType: claim.claim_type,
      claimKind: claim.claim_kind,
      summary: claim.summary,
      quote: quoteOf(claim),
    })),
    newClaimsGained: newClaimsGained.slice(0, 200).map((claim) => ({
      id: claim.id,
      status: claim.status,
      claimType: claim.claim_type,
      claimKind: claim.claim_kind,
      summary: claim.summary,
      quote: quoteOf(claim),
    })),
    assessment: assess(oldClaims, newClaims, newData, duplicateQuoteGroups),
  };

  fs.writeFileSync(path.join(outDir, 'comparison-summary.json'), `${JSON.stringify(comparison, null, 2)}\n`);
  fs.writeFileSync(path.join(outDir, 'comparison-summary.md'), comparisonMd(comparison));
  console.log(JSON.stringify({
    oldTotal: comparison.old.total,
    newTotal: comparison.new.total,
    exactSummaryOverlap: comparison.overlap.exactSummaryCount,
    normalizedQuoteOverlap: comparison.overlap.normalizedQuoteCount,
    duplicateQuoteGroups: duplicateQuoteGroups.length,
    macroRelationships: comparison.new.macroRelationships,
    coverageFindings: comparison.new.coverageFindings,
  }, null, 2));
}

function assess(oldClaims, newClaims, newData, duplicateQuoteGroups) {
  const oldTotal = oldClaims.length;
  const newTotal = newClaims.length;
  const macroCount = newData.summary.macroRelationships;
  const findingCount = newData.summary.coverageFindings;
  const policyCount = newClaims.filter((claim) => claim.claim_kind === 'policy').length;
  const duplicateQuoteClaimCount = duplicateQuoteGroups.reduce((sum, group) => sum + group.count, 0);
  const volumeRatio = oldTotal ? newTotal / oldTotal : null;
  const notes = [];

  if (volumeRatio !== null && volumeRatio > 1.5) {
    notes.push(`Claim volume increased by ${volumeRatio.toFixed(2)}x, so review load increased materially.`);
  } else if (volumeRatio !== null && volumeRatio < 0.8) {
    notes.push(`Claim volume decreased to ${volumeRatio.toFixed(2)}x of the old set.`);
  } else {
    notes.push('Claim volume stayed in roughly the same band.');
  }
  if (macroCount > 0) {
    notes.push(`The rerun produced ${macroCount} macro relationship rows, which is evidence of higher-level workflow capture.`);
  } else {
    notes.push('The rerun produced no macro relationship rows tied to this document.');
  }
  if (findingCount > 0) {
    notes.push(`The rerun produced ${findingCount} coverage finding rows.`);
  } else {
    notes.push('The rerun produced no coverage findings tied to this document.');
  }
  if (policyCount > 0) {
    notes.push(`${policyCount} new claims are labeled policy; visual-plan guidance says ordinary visual arrows should usually be observed_practice unless the source explicitly signals policy.`);
  }
  if (duplicateQuoteClaimCount > 0) {
    notes.push(`${duplicateQuoteClaimCount} new claims share duplicate quote spans across the top duplicate groups, indicating remaining atomic duplication.`);
  }

  let verdict = 'mixed';
  if (macroCount > 0 && duplicateQuoteClaimCount < newTotal * 0.25) verdict = 'improved_holistic_understanding';
  if (macroCount === 0 && volumeRatio !== null && volumeRatio > 1.2) verdict = 'mostly_increased_atomic_volume';

  return { verdict, notes };
}

function comparisonMd(comparison) {
  const lines = [
    '# Comparison Summary',
    '',
    `Generated: ${comparison.generatedAt}`,
    `Document ID: ${comparison.documentId}`,
    '',
    '## Counts',
    '',
    `- Old claims: ${comparison.old.total}`,
    `- New claims: ${comparison.new.total}`,
    `- Exact summary overlap: ${comparison.overlap.exactSummaryCount}`,
    `- Normalized quote overlap: ${comparison.overlap.normalizedQuoteCount}`,
    `- New source outlines: ${comparison.new.outlines}`,
    `- New macro relationships: ${comparison.new.macroRelationships}`,
    `- New coverage findings: ${comparison.new.coverageFindings}`,
    '',
    '## Old Counts By Status / Type / Kind',
    '',
    '```json',
    JSON.stringify(comparison.old.counts.byStatusTypeKind, null, 2),
    '```',
    '',
    '## New Counts By Status / Type / Kind',
    '',
    '```json',
    JSON.stringify(comparison.new.counts.byStatusTypeKind, null, 2),
    '```',
    '',
    '## New Counts By Domain',
    '',
    '```json',
    JSON.stringify(comparison.new.counts.byDomain, null, 2),
    '```',
    '',
    '## Obvious Duplicates In New Claims',
    '',
  ];

  if (!comparison.obviousDuplicatesInNewClaims.duplicateSummaryGroups.length && !comparison.obviousDuplicatesInNewClaims.duplicateQuoteGroups.length) {
    lines.push('No exact normalized summary duplicate groups were found. Duplicate quote groups are also empty.');
  } else {
    for (const group of comparison.obviousDuplicatesInNewClaims.duplicateSummaryGroups.slice(0, 20)) {
      lines.push(`- ${group.count}x same summary: ${group.summary}`);
    }
    for (const group of comparison.obviousDuplicatesInNewClaims.duplicateQuoteGroups.slice(0, 20)) {
      lines.push(`- ${group.count}x same quote: ${group.quote}`);
    }
  }

  lines.push('', '## Newly Captured Important Relationships', '');
  if (comparison.newlyCapturedImportantRelationships.length) {
    for (const rel of comparison.newlyCapturedImportantRelationships) {
      lines.push(`- ${rel.status} / ${rel.relationshipType}: ${rel.summary}`);
    }
  } else {
    lines.push('No macro relationship rows are tied to the new snapshot.');
  }

  lines.push('', '## Old Claims Lost', '');
  for (const claim of comparison.oldClaimsLost.slice(0, 80)) {
    lines.push(`- ${claim.claimType} / ${claim.claimKind}: ${claim.summary}`);
  }
  if (comparison.oldClaimsLost.length > 80) {
    lines.push(`- ... ${comparison.oldClaimsLost.length - 80} more in comparison-summary.json`);
  }

  lines.push('', '## Assessment', '');
  lines.push(`Verdict: ${comparison.assessment.verdict}`);
  for (const note of comparison.assessment.notes) lines.push(`- ${note}`);
  lines.push('');
  return `${lines.join('\n')}\n`;
}

try {
  if (mode === 'compare') await compareSnapshots();
  else await exportSnapshot(mode);
} finally {
  await sql.end();
}

