+    /owner|ownership|role|responsib|swimlane|team/i.test(text) ? 'ownership_and_roles' : null,
+    /depend|sequence|flow|order|stage|timeline/i.test(text) ? 'dependencies_and_sequence' : null,
+    /system|data|entry|platform|dflow|coldlion|clickup|masterdata/i.test(text)
+      ? 'systems_and_data_entry'
+      : null,
+    /definition|acronym|term|alias|means/i.test(text) ? 'definitions_and_acronyms' : null,
+    /customer|licensor|risk|buyer|client/i.test(text) ? 'customer_or_licensor_risk' : null,
+    /contradiction|tension|conflict|inconsistent/i.test(text) ? 'contradictions_and_tensions' : null,
