  VISUAL_UNDERSTANDING_SYSTEM_PROMPT,
  buildVisualUnderstandingRequest,
} from '../prompts/visual-understanding';

function assert(cond: unknown, msg: string): asserts cond {
  if (!cond) {
    console.error(`x ${msg}`);
    process.exit(1);
  }
  console.log(`ok ${msg}`);
}

function includesAll(text: string, phrases: string[]): boolean {
  const lower = text.toLowerCase();
  return phrases.every((phrase) => lower.includes(phrase.toLowerCase()));
}

async function main() {
  console.log('Visual understanding prompt gate\n');

  assert(
    VISUAL_UNDERSTANDING_PROMPT_VERSION === 'visual-understanding-v1',
    'has a dedicated visual prompt version',
  );
  assert(
    !VISUAL_UNDERSTANDING_PROMPT_VERSION.includes('extraction'),
    'visual prompt version is separate from extraction prompt versions',
  );
  assert(
    includesAll(VISUAL_UNDERSTANDING_SYSTEM_PROMPT, [
      'Infer the artifact type and visual grammar',
      'Inspect the entire visual source',
      'Explain ambiguity instead of guessing',
      'Quote-friendly final rendering rules',
      'FINAL FAITHFUL RENDERING',
      'FINAL SELF-CHECK',
      'Do not duplicate the same relationship',
    ]),
    'prompt requires holistic, faithful, quote-friendly visual output',
  );
  assert(
    !/rfq|licensor|price|factory/i.test(VISUAL_UNDERSTANDING_SYSTEM_PROMPT),
    'prompt avoids business/swimlane-specific source concepts',
