import fs from 'node:fs';
import path from 'node:path';
import { createRequire } from 'node:module';

const require = createRequire(path.join(process.cwd(), 'packages/db/package.json'));
const postgres = require('postgres');

const url = process.env.PROD_URL;
const outDir = process.env.OUT_DIR || process.cwd();
if (!url) throw new Error('Set PROD_URL');

const sql = postgres(url, { max: 1, prepare: false, connect_timeout: 30 });

try {
  const modelRuns = await sql.unsafe(`
    select *
    from model_runs
    where created_at >= '2026-07-03T02:40:00Z'::timestamptz
      and task_type in (
        'macro-relationship',
        'macro-relationship-extraction',
        'source-coverage-audit',
        'coverage_audit'
      )
    order by created_at, id
  `);
  const modelRunAttempts = await sql.unsafe(`
    select *
    from model_run_attempts
    where created_at >= '2026-07-03T02:40:00Z'::timestamptz
      and task_type in (
        'macro-relationship',
        'macro-relationship-extraction',
        'source-coverage-audit',
        'coverage_audit'
      )
    order by created_at, id
  `);
  const out = {
    generatedAt: new Date().toISOString(),
    modelRuns,
    modelRunAttempts,
  };
  fs.writeFileSync(
    path.join(outDir, 'failed-followup-model-attempts-after-rerun.json'),
    `${JSON.stringify(out, null, 2)}\n`,
  );
  console.log(JSON.stringify({
    modelRuns: modelRuns.length,
    modelRunAttempts: modelRunAttempts.length,
  }, null, 2));
} finally {
  await sql.end();
}

